1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	};
8	
9	export function processScenario(scenario: any): unknown {
10	  const step = scenario.steps[0];
11	  const items = step.items;
12	
13	  const basePremium = items.reduce(
14	    (sum: number, item: { type: string }) => sum + BASE_PREMIUM[item.type],
15	    0,
16	  );
17	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
18	  const premium = basePremium + firstInsurance + PROCESSING_FEE;
19	
20	  return [{ premium }];
21	}
